import fetch from 'node-fetch'; // Or use the native fetch in modern Node.js environments

async function generateContentWithExaGrounding(promptText: string) {
  if (!process.env.GOOGLE_CLOUD_API_KEY) {
    throw new Error('GOOGLE_CLOUD_API_KEY environment variable is not set.');
  }
  if (!process.env.EXA_API_KEY) {
    throw new Error('EXA_API_KEY environment variable is not set.');
  }

  const API_ENDPOINT = 'https://aiplatform.googleapis.com/v1/publishers/google/models/gemini-2.5-flash:generateContent';
  const GOOGLE_API_KEY = process.env.GOOGLE_CLOUD_API_KEY;
  const EXA_API_KEY = process.env.EXA_API_KEY;

  const requestBody = {
    contents: [
      {
        role: 'user',
        parts: [{ text: promptText }],
      },
    ],
    tools: [
      {
        exaAiSearch: {
          api_key: EXA_API_KEY,
          customConfigs: {
            type: 'auto',
            numResults: 5,
            contents: {
              highlights: {
                maxCharacters: 2000,
              },
            },
          },
        },
      },
    ],
  };

  try {
    const response = await fetch(API_ENDPOINT, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-goog-api-key': GOOGLE_API_KEY,
      },
      body: JSON.stringify(requestBody),
    });

    if (!response.ok) {
      const errorData = await response.json();
      console.error('Error response from Gemini API:', errorData);
      throw new Error(`Gemini API request failed with status ${response.status}: ${JSON.stringify(errorData)}`);
    }

    const data = await response.json();
    console.log('Gemini API response:', JSON.stringify(data, null, 2));
    return data;
  } catch (error) {
    console.error('Failed to call Gemini API:', error);
    throw error;
  }
}

// Example usage:
// generateContentWithExaGrounding('What are the latest advancements in AI ethics?');
